def get_cooldown_codes() -> dict:
    """获取止损冷却期内的股票代码 → {code: 剩余天数}"""
    cooldown_days = TRADING_RULES.get("rebuy_cooldown_days", 30)
    tx_file = BASE_DIR / "transactions.json"
    if not tx_file.exists():
        return {}
    try:
        with open(tx_file, 'r') as f:
            transactions = json.load(f)
        from datetime import timedelta
        now = datetime.now()
        cooldown = {}
        for t in transactions:
            if t.get("type") != "sell":
                continue
            reasons = t.get("reasons", [])
            # 止损卖出：reasons含"止损"，或pnl_pct < stop_loss_pct
            is_stop_loss = any("止损" in str(r) for r in reasons)
            if not is_stop_loss:
                pnl = t.get("pnl_pct", 0)
                if isinstance(pnl, (int, float)) and pnl < TRADING_RULES.get("stop_loss_pct", -0.03) * 100:
                    is_stop_loss = True
            if not is_stop_loss:
                continue
            try:
                sell_date = datetime.fromisoformat(t["timestamp"][:10])
            except (ValueError, KeyError):
                continue
            days_since = (now - sell_date).days
            remaining = cooldown_days - days_since
            if remaining > 0:
                code = t["code"]
                cooldown[code] = max(cooldown.get(code, 0), remaining)
        return cooldown
    except Exception:
        return {}

